import pytest
from plugins.base import Extension
from plugins.log_plugin import LogPlugin
from plugins.filter_plugin import FilterPlugin
from plugins.transform_plugin import TransformPlugin
from plugins.audit_plugin import AuditPlugin
from plugins.loader import PluginLoader
from plugins.chain import PluginChain


class TestExtension:
    def test_not_implemented(self):
        p = Extension()
        with pytest.raises(NotImplementedError):
            p.run({"x": 1})

    def test_describe(self):
        p = Extension()
        assert "base" in p.describe()


class TestLogPlugin:
    def test_logs(self):
        p = LogPlugin()
        p.run({"msg": "hello"})
        assert len(p.entries) == 1

    def test_passthrough(self):
        p = LogPlugin()
        result = p.run({"v": 42})
        assert result == {"v": 42}


class TestFilterPlugin:
    def test_passes(self):
        p = FilterPlugin(predicate=lambda payload: payload.get("ok"))
        assert p.run({"ok": True}) == {"ok": True}

    def test_blocks(self):
        p = FilterPlugin(predicate=lambda payload: payload.get("ok"))
        assert p.run({"ok": False}) is None


class TestTransformPlugin:
    def test_transforms(self):
        p = TransformPlugin(func=lambda payload: {"doubled": payload["v"] * 2})
        assert p.run({"v": 5}) == {"doubled": 10}


class TestAuditPlugin:
    def test_counts(self):
        p = AuditPlugin()
        p.run({"a": 1})
        p.run({"b": 2})
        assert p.count == 2
        assert p.last_seen == {"b": 2}


class TestLoader:
    def test_register_and_run(self):
        loader = PluginLoader()
        loader.register(LogPlugin())
        result = loader.run_all({"v": 1})
        assert result == {"v": 1}

    def test_type_check(self):
        loader = PluginLoader()
        with pytest.raises(TypeError):
            loader.register("not a plugin")


class TestChain:
    def test_chain_execution(self):
        chain = PluginChain()
        chain.add(LogPlugin())
        chain.add(TransformPlugin(func=lambda payload: {"result": payload["v"] + 1}))
        result = chain.run({"v": 10})
        assert result == {"result": 11}
